tool_input.content:
#!/usr/bin/env bash
# Process hook
set -euo pipefail

read_input() { cat; }
HOOK_INPUT=$(read_input)
FILE_PATH=$(echo "$HOOK_INPUT" | jq -r '.tool_input.file_path // empty')
[[ -z "$FILE_PATH" ]] && exit 0

check_file() {
    local f="$1"
    echo "checking $f"
}

for i in {1..10}; do
    check_file "/path/$i"
done

process_main() {
    local input="$1"
    echo "processing: $input"
    return 0
}

handle_error() {
    local msg="$1"
    echo "ERROR: $msg" >&2
}

validate_input() {
    local v="$1"
    [[ -n "$v" ]] || { handle_error "empty input"; return 1; }
    return 0
}

main() {
    validate_input "$HOOK_INPUT" || exit 1
    process_main "$HOOK_INPUT"
    echo '{}'
}

main "$@"
